// mm/src/api/listDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

/**
 * Normalize backend document object
 * Backend returns:
 *   - DocumentId
 *   - OrigionalFileName
 *   - FileSize
 */
function normalizeDocument(raw = {}) {
  return {
    documentId: raw.DocumentId || raw.documentId || null,
    filename: raw.OrigionalFileName ||null,
    size: raw.FileSize ?? raw.size ?? null,
  };
}

/**
 * List all documents for the authenticated user
 *
 * Endpoint: listDocuments.php
 * Requires:
 *   - Authorization: Bearer <token>
 *   - accessToken (query param)  <-- your PHP expects this too
 */
export async function listDocuments() {
  const url = `${API_BASE}/listDocuments.php`;

  try {
    const response = await withAuthRetry(async () => {
      const accessToken = await getAccessToken(); // ✅ MUST await
      if (!accessToken) throw new Error('Missing access token');

      console.log('📄 listDocuments request:', {
        url,
        tokenPrefix: `${accessToken.slice(0, 10)}...`,
      });

      return axios.get(url, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          Accept: 'application/json',
        },
        params: { accessToken }, // ✅ PHP expects it
      });
    });

    // Some PHP endpoints return a JSON string; normalize that too
    const rawData =
      typeof response.data === 'string' ? safeJsonParse(response.data, []) : response.data;

    const rawDocs = Array.isArray(rawData) ? rawData : rawData?.documents || [];
    const documents = (rawDocs || []).map(normalizeDocument);

    console.log('✅ listDocuments success:', {
      status: response.status,
      rawType: typeof response.data,
      rawData,
      count: documents.length,
      documents,
    });

    return {
      success: true,
      data: { documents },
      status: response.status,
    };
  } catch (err) {
    const status = err?.response?.status ?? null;
    const backendData = err?.response?.data ?? null;

    console.error('listDocuments failed:', {
      status,
      backendData,
      message: err?.message,
    });

    return {
      success: false,
      error: backendData || err?.message || 'Failed to list documents',
      status,
    };
  }
}

function safeJsonParse(v, fallback) {
  try {
    return JSON.parse(v);
  } catch {
    return fallback;
  }
}
